# stub/model_stub.py — FastAPI server that mimics the OpenAI chat completion API
from fastapi import FastAPI
from pydantic import BaseModel
import json, random, time

app = FastAPI()

FIXTURE_RESPONSES = {
    "default": "This is a stub response for testing.",
    "rag_query": "Based on the provided context, the answer is: [fixture response].",
    "safety_test": "I cannot help with that request.",
}

class Message(BaseModel):
    role: str
    content: str

class ChatRequest(BaseModel):
    model: str
    messages: list[Message]
    temperature: float = 0.0
    max_tokens: int = 512

@app.post("/v1/chat/completions")
def chat(req: ChatRequest) -> dict:
    # Simulate latency (configurable via env)
    import os
    time.sleep(float(os.environ.get("STUB_LATENCY_MS", "50")) / 1000)

    # Route to fixture based on last user message keywords
    last = req.messages[-1].content.lower()
    key = "safety_test" if "ignore" in last or "bypass" in last else \
          "rag_query" if "context" in last else "default"

    return {
        "id": f"stub-{random.randint(1000, 9999)}",
        "object": "chat.completion",
        "model": req.model,
        "choices": [{
            "index": 0,
            "message": {"role": "assistant", "content": FIXTURE_RESPONSES[key]},
            "finish_reason": "stop",
        }],
        "usage": {"prompt_tokens": 50, "completion_tokens": 20, "total_tokens": 70},
    }

@app.get("/health")
def health() -> dict:
    return {"status": "ok", "mode": "stub"}

