"""Run as a cron job every 30 minutes. Deletes expired sandbox namespaces."""
import json, os, subprocess
from datetime import datetime, timezone, timedelta

TTL_RULES = {
    "pr-": timedelta(hours=48),         # PR sandboxes: 48h from last push
    "eval-": timedelta(hours=4),        # Eval sandboxes: 4h absolute max
    "feature-": timedelta(days=30),     # Feature sandboxes: 30 days idle
}

def list_sandbox_namespaces() -> list[dict]:
    raw = subprocess.check_output(
        ["kubectl", "get", "namespaces", "-o", "json"]
    )
    ns_list = json.loads(raw)["items"]
    return [
        {
            "name": ns["metadata"]["name"],
            "created": ns["metadata"]["creationTimestamp"],
            "labels": ns["metadata"].get("labels", {}),
        }
        for ns in ns_list
        if any(ns["metadata"]["name"].startswith(prefix) for prefix in TTL_RULES)
    ]

def should_delete(ns: dict) -> bool:
    name = ns["name"]
    prefix = next(p for p in TTL_RULES if name.startswith(p))
    created = datetime.fromisoformat(ns["created"].replace("Z", "+00:00"))
    ttl = TTL_RULES[prefix]
    age = datetime.now(timezone.utc) - created
    return age > ttl

def cleanup() -> None:
    namespaces = list_sandbox_namespaces()
    to_delete = [ns for ns in namespaces if should_delete(ns)]

    for ns in to_delete:
        print(f"Deleting expired sandbox: {ns['name']}")
        subprocess.run(["kubectl", "delete", "namespace", ns["name"]])

    print(f"Cleanup complete. Deleted {len(to_delete)} of {len(namespaces)} sandboxes.")

if __name__ == "__main__":
    cleanup()
